// Nodo: Preparar Requerimientos API Google Docs
// Referencia ID_Maestro: a0471f13-eb0f-4352-9dbb-c910e702fddb
const data = $input.first().json; 
const transacciones = JSON.parse(data.tabla_transaccion || "[]").filter(t => t.Fecha);

// Calculamos filas (5 transacciones + 1 encabezado)
const numRows = transacciones.length + 1;

return {
  documentId: data.id,
  requests: [
    {
      // Paso A: Borrar el placeholder {{tabla_texto}}
      "replaceAllText": {
        "containsText": { "text": "{{tabla_texto}}", "matchCase": true },
        "replaceText": "" 
      }
    },
    {
      // Paso B: Insertar la estructura de la tabla nativa (5 columnas)
      "insertTable": {
        "rows": numRows,
        "columns": 5,
        "location": { "index": 1 } 
      }
    }
  ]
};

// Nodo: Preparar Datos Demanda y Comandos de Tabla Nativa
// Proyecto: Automatización de Fraudes Bancarios 2026

const item = $input.first().json;
const transacciones = JSON.parse(item.tabla_transaccion || "[]").filter(t => t.Fecha);

// 1. Datos de la Demanda (Textos Simples)
const montoReclamado = item.monto_reclamado || 0;
const montoFormateado = montoReclamado.toLocaleString('es-CL');
const fechaAviso = item.fecha_aviso ? item.fecha_aviso.split('T')[0] : "";

// Procesar Puntos de Ataque para que se vean como párrafos legales
let puntosAtaqueTexto = "";
try {
  const puntos = JSON.parse(item.puntos_ataque || "[]");
  puntosAtaqueTexto = puntos.join('\n\n');
} catch (e) {
  puntosAtaqueTexto = item.puntos_ataque || "";
}

// 2. Construcción de Comandos "Language" de Google Docs (batchUpdate)
// Primero eliminamos el marcador {{tabla_texto}} e insertamos una tabla real
let googleDocsRequests = [
  {
    // Buscamos el marcador y lo vaciamos para dejar espacio a la tabla
    replaceAllText: {
      containsText: { text: "{{tabla_texto}}", matchCase: true },
      replaceText: ""
    }
  },
  {
    // Insertamos la estructura de la tabla nativa
    // Definimos 5 columnas: Fecha, Tarjeta, Monto, Comercio, Canal
    insertTable: {
      rows: transacciones.length + 1, // +1 para la fila de encabezados
      columns: 5,
      location: { index: 1 } // Se recomienda insertar al inicio o calcular el índice
    }
  }
];

// 3. Salida final para n8n
return {
  json: {
    documentId: item.id, // ID del documento copiado (ej: Demanda_Sixbel...)
    id_maestro: item.id_maestro,

    // Variables para el nodo de Google Docs (Update)
    reemplazos_texto: {
      tribunal: item.tribunal || "Juzgado de Policía Local de Peñalolén",
      nombre_demandado: item.nombre_demandado,
      rut_demandado: item.rut_demandado,
      domicilio_demandado: item.domicilio_demandado,
      monto_formateado: `$${montoFormateado}`,
      fecha_aviso: fechaAviso,
      canal_operacion: item.canal_operacion,
      relato_hechos: item.relato_hechos,
      argumento_banco: item.argumento_banco,
      puntos_ataque_limpio: puntosAtaqueTexto
    },

    // Comandos para el nodo HTTP Request (API batchUpdate)
    requests_google_api: googleDocsRequests
  }
};

// Nodo "Code" en n8n
// Conectar después del "Execute Workflow Trigger"

for (const item of $input.all()) {

  // 1. Parsear la tabla de transacciones (de String a Array de Objetos)
  // Esto permite que el iterador {#tabla_transaccion_array} de Word funcione.
  if (typeof item.json.tabla_transaccion === 'string') {
    try {
      item.json.tabla_transaccion_array = JSON.parse(item.json.tabla_transaccion);
    } catch (error) {
      item.json.tabla_transaccion_array = [];
    }
  }

  // 2. Parsear los Puntos de Ataque
  // Vienen como un Array stringificado. Los unimos con doble salto de línea (\n\n)
  // para que se inyecten como párrafos limpios en el documento Word.
  if (typeof item.json.puntos_ataque === 'string') {
    try {
      const puntosArray = JSON.parse(item.json.puntos_ataque);
      item.json.puntos_ataque_formateado = puntosArray.join('\n\n');
    } catch (error) {
      item.json.puntos_ataque_formateado = item.json.puntos_ataque;
    }
  }

  // 3. Formatear el monto con separadores de miles (Estilo Chile: $3.021.640)
  if (item.json.monto_reclamado) {
    item.json.monto_formateado = item.json.monto_reclamado.toLocaleString('es-CL');
  }
}

return $input.all();
